#include <bits/stdc++.h>
using namespace std;
int main(){int n,m;cin>>n>>m;vector<string>g(n);for(auto&s:g)cin>>s;string out;for(int i=0;i<n;i++){for(int j=0;j<m;j++){if(g[i][j]=='*'){out+='*';continue;}int c=0;for(int dx=-1;dx<=1;dx++)for(int dy=-1;dy<=1;dy++){if(!dx&&!dy)continue;int ni=i+dx,nj=j+dy;if(ni>=0&&nj>=0&&ni<n&&nj<m&&g[ni][nj]=='*')c++;}out+=('0'+c);}out+='\n';}cout<<out;}
